esqlQuery.esql:
FROM metrics-oracledbreceiver.otel-*
// Transaction usage and limit are in separate TSDB document groups; aggregate across time window
| STATS usage = MAX(oracledb.transactions.usage),
        limit_val = MAX(oracledb.transactions.limit)
        BY oracledb.instance.name, host.name
// Exclude unlimited (-1)
| WHERE limit_val > 0
// Utilisation > 85% — transaction limit exhaustion prevents new transactions
// Adjust threshold to tune sensitivity
| EVAL utilisation_pct = ROUND(usage * 100.0 / limit_val, 1)
| WHERE utilisation_pct > 85
| SORT utilisation_pct DESC
